"""Code-based evaluation criterion executed in sandbox."""

from __future__ import annotations

import json
from typing import TYPE_CHECKING, Literal

from pydantic import Field

from h_arcane.core._internal.db.models import CriterionResult, ResourceRecord
from h_arcane.core._internal.evaluation.rules.base import BaseCriterion

if TYPE_CHECKING:
    from h_arcane.core._internal.evaluation.runtime import CriterionRuntime
    from h_arcane.core._internal.evaluation.schemas import CriterionContext


class CodeRule(BaseCriterion):
    """Code-based evaluation rule generated by LLM.

    The LLM generates Python source code as a string, which will be
    compiled into an executable function during conversion.
    """

    type: Literal["code"] = "code"
    code: str = Field(
        description=(
            "Python source defining: evaluate(task_input: str, agent_reasoning: str, "
            "output_files: dict[str, bytes]) -> float | tuple[float, str]\n\n"
            "Function receives:\n"
            "  - task_input: Original task description\n"
            "  - agent_reasoning: Worker's reasoning/output text\n"
            "  - output_files: dict mapping file paths to bytes\n\n"
            "Must return float in [0, weight] or tuple[float, str] with feedback.\n"
            "Can import: re, json, pandas as pd, numpy as np, pdfplumber, docx, io"
        ),
    )

    async def evaluate(
        self,
        runtime: "CriterionRuntime",
        context: "CriterionContext",
    ) -> CriterionResult:
        """Evaluate code criterion in sandbox."""
        await runtime.ensure_sandbox()
        await runtime.upload_files(context.agent_outputs)

        code = self._build_evaluation_code(
            task_input=context.task_input,
            agent_reasoning=context.agent_reasoning,
            agent_outputs=context.agent_outputs,
            max_score=context.max_score,
        )

        exec_result = await runtime.execute_code(code)
        score, feedback, resource_ids = self._parse_result(
            exec_result.stdout,
            exec_result.stderr,
            context.max_score,
        )

        return CriterionResult(
            run_id=context.run_id,
            stage_num=context.stage_idx,
            stage_name=context.stage_name,
            criterion_num=context.criterion_idx,
            criterion_type="code_rule",
            criterion_description=self.description,
            score=score,
            max_score=context.max_score,
            feedback=feedback,
            evaluation_input=code,
            evaluated_action_ids=[],
            evaluated_resource_ids=resource_ids,
        )

    def _build_evaluation_code(
        self,
        task_input: str,
        agent_reasoning: str,
        agent_outputs: list[ResourceRecord],
        max_score: float,
    ) -> str:
        """Build Python code string for sandbox execution."""
        evaluated_resource_ids = [str(r.id) for r in agent_outputs]

        # Build file loading code with error handling
        file_loading_code_parts = []
        for resource in agent_outputs:
            file_loading_code_parts.append(
                f"try:\n"
                f'    with open("/evaluation/{resource.name}", "rb") as f:\n'
                f'        output_files["/evaluation/{resource.name}"] = f.read()\n'
                f'        print(f"Loaded file: {resource.name} ({{len(output_files[\\"/evaluation/{resource.name}\\"])}} bytes)")\n'
                f"except Exception as e:\n"
                f'    print(f"Warning: Failed to load {resource.name}: {{e}}", file=sys.stderr)\n'
            )
        file_loading_code = "\n".join(file_loading_code_parts)

        code = f"""import json
import re
import sys
import traceback
import pandas as pd
import numpy as np
import pdfplumber
from docx import Document
from io import BytesIO

# Set max_score for use in feedback messages
max_score = {max_score}

{self.code}

# Prepare output_files dict
output_files = {{}}
print(f"Loading {{len({json.dumps([r.name for r in agent_outputs])})}} files into output_files...")
{file_loading_code}
print(f"Loaded {{len(output_files)}} files successfully")

# Execute evaluation
try:
    result = evaluate(
        task_input={json.dumps(task_input)},
        agent_reasoning={json.dumps(agent_reasoning)},
        output_files=output_files
    )
    
    if isinstance(result, tuple):
        score, feedback = result
    else:
        score = float(result)
        feedback = f"Code rule '{self.name}' scored {{score}}/{{max_score}}"
    
    # Ensure score is in valid range
    score = max(0.0, min(score, max_score))
    
    print(json.dumps({{
        "score": score,
        "feedback": feedback,
        "evaluated_resource_ids": {json.dumps(evaluated_resource_ids)}
    }}))
except Exception as e:
    error_msg = str(e)
    full_traceback = traceback.format_exc()
    print(json.dumps({{
        "score": 0.0,
        "feedback": f"Error executing code rule: {{error_msg}}\\n\\nFull traceback:\\n{{full_traceback}}",
        "evaluated_resource_ids": []
    }}))
"""
        return code

    def _parse_result(
        self,
        stdout: list[str],
        stderr: list[str],
        max_score: float,
    ) -> tuple[float, str, list[str]]:
        """Parse result from code rule execution."""
        output = "\n".join(stdout)
        stderr_output = "\n".join(stderr) if stderr else ""

        try:
            # Find JSON in stdout
            lines = output.strip().split("\n")
            json_line = None
            for line in reversed(lines):
                line = line.strip()
                if line.startswith("{") or line.startswith("["):
                    json_line = line
                    break

            if json_line:
                result_data = json.loads(json_line)
                score = min(max(float(result_data["score"]), 0.0), max_score)
                feedback = result_data["feedback"]
                evaluated_resource_ids = result_data.get("evaluated_resource_ids", [])

                # Include stderr in feedback if present (for debugging)
                if stderr_output and "Error" not in feedback:
                    feedback = f"{feedback}\n\n[Debug stderr: {stderr_output[:200]}]"

                return score, feedback, evaluated_resource_ids
            else:
                # No JSON found - return error with full context
                error_msg = f"No JSON output found. Stdout: {output[:500]}"
                if stderr_output:
                    error_msg += f"\nStderr: {stderr_output[:500]}"
                raise json.JSONDecodeError(error_msg, output, 0)
        except (json.JSONDecodeError, KeyError, ValueError) as e:
            # Return detailed error information
            error_msg = stderr_output if stderr_output else str(e)
            if not error_msg:
                error_msg = f"Parse error: {e}\nStdout: {output[:500]}"
            return 0.0, f"Error evaluating code rule: {error_msg}", []
